    @app.get("/documents")
    def query_documents():
        q = (request.args.get("q") or "").strip()
        status = (request.args.get("status") or "").strip().lower()
        tag = (request.args.get("tag") or "").strip()
        author_id = as_oid_or_none(request.args.get("author_id"))
        slug = (request.args.get("slug") or "").strip()
        ids = (request.args.get("ids") or "").strip()
        created_from = parse_dt(request.args.get("created_from"))
        created_to = parse_dt(request.args.get("created_to"))
        published_only = parse_bool(request.args.get("published_only"), None)

        limit = max(1, min(200, parse_int(request.args.get("limit"), 50)))
        skip = max(0, parse_int(request.args.get("skip"), 0))
        sort = (request.args.get("sort") or "created_at").strip()
        direction = -1 if (request.args.get("dir") or "desc").lower() == "desc" else 1

        filter_doc: Dict[str, Any] = {}

        if ids:
            try:
                id_list = [oid(x.strip()) for x in ids.split(",") if x.strip()]
                filter_doc["_id"] = {"$in": id_list} if id_list else {"$in": []}
            except Exception:
                return json_error("invalid_ids", 400)

        if slug:
            filter_doc["slug"] = slug

        if status:
            if status not in ("draft", "published", "archived"):
                return json_error("invalid_status", 400)
            filter_doc["status"] = status

        if published_only is True:
            filter_doc["status"] = "published"

        if tag:
            filter_doc["tags"] = tag

        if author_id is not None:
            filter_doc["author_id"] = author_id

        if created_from or created_to:
            filter_doc["created_at"] = {}
            if created_from:
                filter_doc["created_at"]["$gte"] = created_from
            if created_to:
                filter_doc["created_at"]["$lte"] = created_to

        find_kwargs: Dict[str, Any] = {}

        if q:
            find_kwargs["projection"] = {"score": {"$meta": "textScore"}}
            cursor = documents.find({"$and": [filter_doc, {"$text": {"$search": q}}]}, **find_kwargs).sort(
                [("score", {"$meta": "textScore"}), ("created_at", -1)]
            )
        else:
            allowed_sorts = {"created_at", "updated_at", "published_at", "title"}
            if sort not in allowed_sorts:
                sort = "created_at"
            cursor = documents.find(filter_doc).sort(sort, direction)

        total = documents.count_documents({"$and": [filter_doc, {"$text": {"$search": q}}]} if q else filter_doc)
        items = [to_public_doc(d) for d in cursor.skip(skip).limit(limit)]
        return jsonify({"items": items, "total": total, "limit": limit, "skip": skip})

