        limit = max(1, min(200, parse_int(request.args.get("limit"), 50)))

        match: Dict[str, Any] = {}
        if status:
            match["status"] = status
        if published_from or published_to:
            match["published_at"] = {}
            if published_from:
                match["published_at"]["$gte"] = published_from
            if published_to:
                match["published_at"]["$lte"] = published_to

        pipeline: List[Dict[str, Any]] = [
            {"$match": match} if match else {"$match": {}},
            {"$group": {"_id": "$author_id", "count": {"$sum": 1}, "latest": {"$max": "$published_at"}}},
            {"$sort": {"count": -1, "latest": -1}},
            {"$limit": limit},
            {
                "$lookup": {
                    "from": "users",
                    "localField": "_id",
                    "foreignField": "_id",
                    "as": "author",
                }
            },
            {"$unwind": {"path": "$author", "preserveNullAndEmptyArrays": True}},
            {
                "$project": {
                    "_id": 0,
                    "author_id": {"$toString": "$_id"},
                    "count": 1,
                    "latest": 1,
                    "author": {
                        "id": {"$toString": "$author._id"},
                        "email": "$author.email",
                        "username": "$author.username",
                        "display_name": "$author.display_name",
                    },
                }
            },
        ]

        results = list(documents.aggregate(pipeline))
        for r in results:
            if isinstance(r.get("latest"), datetime):
                r["latest"] = r["latest"].isoformat() + "Z"
        return jsonify({"items": results, "pipeline": pipeline})

