    @app.get("/analytics/search-top-terms")
    def analytics_search_top_terms():
        q = (request.args.get("q") or "").strip()
        if not q:
            return json_error("q_required", 400)

        status = (request.args.get("status") or "published").strip().lower()
        if status and status not in ("draft", "published", "archived"):
            return json_error("invalid_status", 400)

        limit = max(1, min(100, parse_int(request.args.get("limit"), 20)))

        match: Dict[str, Any] = {"$text": {"$search": q}}
        if status:
            match = {"$and": [match, {"status": status}]}

        pipeline: List[Dict[str, Any]] = [
            {"$match": match},
            {"$addFields": {"score": {"$meta": "textScore"}}},
            {"$sort": {"score": -1, "published_at": -1, "created_at": -1}},
            {"$limit": limit},
            {"$project": {"_id": 0, "id": {"$toString": "$_id"}, "slug": 1, "title": 1, "score": 1}},
        ]

        results = list(documents.aggregate(pipeline))
        return jsonify({"items": results, "pipeline": pipeline})

